-- -----------------------------------------------------------------------------
-- CTE 04 - source_positions
-- Raw NAV rows with optional fund and NAV-date filters applied.
source_positions as (
    select p.*
    from nav.positions as p
    cross join params
    where (params.fund_filter is null or p.fund_code = params.fund_filter)
      and (params.requested_nav_date is null or p.nav_date = params.requested_nav_date)
),
-- -----------------------------------------------------------------------------
-- CTE 05 - latest_nav_by_fund
-- Selects the requested NAV date or each fund's latest available date.
latest_nav_by_fund as (
    select
        source_positions.fund_code,
        coalesce((select requested_nav_date from params), max(source_positions.nav_date)) as nav_date
    from source_positions
    group by source_positions.fund_code
),
-- -----------------------------------------------------------------------------
-- CTE 06 - latest_upload_by_fund
-- Keeps the latest SFTP upload for the selected NAV date per fund.
latest_upload_by_fund as (
    select
        source_positions.fund_code,
        source_positions.nav_date,
        max(source_positions.sftp_upload_timestamp) as sftp_upload_timestamp
    from source_positions
    inner join latest_nav_by_fund latest
        on latest.fund_code = source_positions.fund_code
       and latest.nav_date = source_positions.nav_date
    group by source_positions.fund_code, source_positions.nav_date
),
-- -----------------------------------------------------------------------------
-- CTE 07 - selected_positions
-- Limits source rows to the selected latest fund uploads.
selected_positions as (
    select source_positions.*
    from source_positions
    inner join latest_upload_by_fund latest
        on latest.fund_code = source_positions.fund_code
       and latest.nav_date = source_positions.nav_date
       and latest.sftp_upload_timestamp = source_positions.sftp_upload_timestamp
),
-- -----------------------------------------------------------------------------
-- CTE 08 - normalized_positions
-- Normalizes product text, option side, contract month, and daily contract fields.
normalized_positions as (
    select
        selected_positions.*,
        upper(regexp_replace(coalesce(selected_positions.product, ''), '[[:space:]]+', ' ', 'g')) as product_norm,
        (
            upper(coalesce(selected_positions.call_put, '')) in ('CALL', 'PUT', 'C', 'P')
            or upper(coalesce(selected_positions.type, '')) like '%OPTION%'
        ) as is_option,
        case
            when upper(coalesce(selected_positions.call_put, '')) in ('CALL', 'C') then 'C'
            when upper(coalesce(selected_positions.call_put, '')) in ('PUT', 'P') then 'P'
            else null
        end as put_call,
        case
            when selected_positions.month_year ~ '^\s*\d{1,2}/\d{1,2}/\d{4}\s*$'
            then to_char(to_date(trim(selected_positions.month_year), 'MM/DD/YYYY'), 'YYYYMM')
            when upper(trim(coalesce(selected_positions.month_year, ''))) ~ '^[A-Z]{3}\d{2}$'
            then to_char(to_date(upper(trim(selected_positions.month_year)), 'MONYY'), 'YYYYMM')
            else null
        end as contract_yyyymm,
        case
            when selected_positions.month_year ~ '^\s*\d{1,2}/\d{1,2}/\d{4}\s*$'
            then extract(day from to_date(trim(selected_positions.month_year), 'MM/DD/YYYY'))::integer
            else null
        end as contract_day
    from selected_positions
),
-- -----------------------------------------------------------------------------
-- CTE 09 - rule_matches
-- Finds the first source-specific product alias for each NAV row.
rule_matches as (
    select
        normalized_positions.*,
        matched_alias.priority as rule_priority,
        matched_alias.match_type as rule_match_type,
        matched_alias.pattern as rule_pattern,
        matched_alias.product_code as matched_product_code
    from normalized_positions
    left join lateral (
        select product_aliases.*
        from product_aliases
        where (
                (
                    product_aliases.match_type = 'exact'
                    and normalized_positions.product_norm = product_aliases.pattern
                )
                or (
                    product_aliases.match_type = 'regex'
                    and normalized_positions.product_norm ~* product_aliases.pattern
                )
            )
          and (
                product_aliases.option_type is null
                or product_aliases.option_type = case when normalized_positions.is_option then 'option' else 'future' end
            )
        order by product_aliases.priority
        limit 1
    ) matched_alias on true
),
-- -----------------------------------------------------------------------------
-- CTE 10 - positions_with_rules
-- Adds derived product, contract, option, and rule-status fields.
positions_with_rules as (
    select
        rule_matches.fund_code,
        rule_matches.source_legal_entity,
        rule_matches.source_file_name,
