-- CTE 12 - final
-- Keeps the raw NAV columns first, then appends generated rule fields for the latest selected upload.
final as (
    select
        -- Raw NAV position columns, kept first and in source-table order.
        fund_code,
        source_legal_entity,
        source_file_name,
        source_file_row_number,
        nav_date,
        sftp_upload_timestamp,
        broker_name,
        account_group,
        account,
        trade_date,
        product_id_internal,
        product,
        type,
        month_year,
        client_symbol,
        strike_price,
        call_put,
        product_currency_1,
        long_short,
        quantity_1,
        counter_currency_ccy2,
        ccy2_long_short,
        ccy2_quantity_2,
        trade_price,
        multiplier_and_tick_value,
        cost_in_native_currency,
        open_exchange_rate,
        cost_in_base_currency,
        market_settlement_price,
        market_value_in_native_currency,
        close_exchange_rate,
        market_value_in_base_currency,
        sector,
        sub_sector,
        country,
        exchange_name,
        source_1_symbol,
        source_3_symbol,
        one_chicago_symbol,
        fas_level,
        option_style,
        created_at,
        updated_at,

        -- Generated NAV rule fields.
        product_code,
        product_family,
        market_name,
        underlying_product_code,
        bbg_exchange_code,
        default_exchange_name,
        contract_yyyymm,
        contract_day,
        put_call,
        strike_price_normalized,
        rule_status,
        rule_priority,
        rule_match_type,
        rule_pattern
    from filtered_positions
    order by
        nav_date desc,
        sftp_upload_timestamp desc,
        fund_code,
        account_group,
        account,
        product_code,
        contract_yyyymm,
        contract_day
)
select * from final;
